# --- 1. 路径和配置处理 ---

def resource_path(relative_path):
    """ 获取资源的绝对路径，兼容开发环境和PyInstaller打包环境 """
    try:
        # PyInstaller 创建一个临时文件夹，并将路径存储在 _MEIPASS
        base_path = sys._MEIPASS
    except Exception:
        # 未打包，使用常规路径
        base_path = os.path.abspath(".")
    
    return os.path.join(base_path, relative_path)

def get_application_path():
    """ 获取应用程序（EXE或脚本）所在的目录 """
    if getattr(sys, 'frozen', False):
        # 如果是打包的 EXE
        return os.path.dirname(sys.executable)
    else:
        # 如果是 .py 脚本
        return os.path.dirname(os.path.abspath(__file__))

# --- 全局配置变量 ---
APP_PATH = get_application_path()
CONFIG_FILE = os.path.join(APP_PATH, 'config.json')
ICON_FILE_NAME = 'icon.ico' # 图标文件必须在同一目录
ICON_PATH_BUNDLED = resource_path(ICON_FILE_NAME) # 打包后在内部的路径

DEFAULT_HOST = "0.0.0.0"
DEFAULT_PORT = 8000
DEFAULT_NAME = "Server"
SPEC_NAME = DEFAULT_NAME
VERSION = "1.1"

def load_config():
    global SPEC_NAME
    """ 加载或创建 config.json """
    if not os.path.exists(CONFIG_FILE):
        print(f"未找到 {CONFIG_FILE}，创建默认配置...")
        config = {"host": DEFAULT_HOST, "port": DEFAULT_PORT, "name": DEFAULT_NAME}
        try:
            with open(CONFIG_FILE, 'w', encoding='utf-8') as f:
                json.dump(config, f, indent=4)
        except Exception as e:
            print(f"创建配置文件失败: {e}")
            return DEFAULT_HOST, DEFAULT_PORT, DEFAULT_NAME
    
    try:
        with open(CONFIG_FILE, 'r', encoding='utf-8') as f:
            config = json.load(f)
            host = config.get("host", DEFAULT_HOST)
            port = int(config.get("port", DEFAULT_PORT))
            name = config.get("name", DEFAULT_NAME)
            SPEC_NAME = name
            return host, port, name
    except Exception as e:
        print(f"加载配置失败: {e}，使用默认配置。")
        return DEFAULT_HOST, DEFAULT_PORT, DEFAULT_NAME

# --- 2. FastAPI 应用程序定义 (与之前相同) ---

app = FastAPI()

def format_speed(speed_bytes_per_sec):
    if speed_bytes_per_sec > 1024 * 1024:
        return f"{speed_bytes_per_sec / (1024 * 1024):.1f} MB/s"
    elif speed_bytes_per_sec > 1024:
        return f"{speed_bytes_per_sec / 1024:.1f} KB/s"
    else:
        return f"{speed_bytes_per_sec:.1f} B/s"

psutil.cpu_percent(interval=None) 
last_net_stats = psutil.net_io_counters()
last_net_time = time.time()

def get_system_stats():
    global last_net_stats, last_net_time
    
    now = datetime.now()
    current_time_str = now.strftime("%Y-%m-%d %H:%M:%S")
    current_week_str = now.strftime("%A")
    
    cpu_usage = psutil.cpu_percent(interval=None)
    memory_usage = psutil.virtual_memory().percent
    
    current_net_stats = psutil.net_io_counters()
    current_net_time = time.time()
    
    time_diff = current_net_time - last_net_time
    sent_diff = current_net_stats.bytes_sent - last_net_stats.bytes_sent
    recv_diff = current_net_stats.bytes_recv - last_net_stats.bytes_recv
    
    up_speed = 0.0
    down_speed = 0.0
    
    if time_diff > 0:
        up_speed = sent_diff / time_diff
        down_speed = recv_diff / time_diff
        
    last_net_stats = current_net_stats
    last_net_time = current_net_time
    
    return {
        "time": current_time_str,
        "name": SPEC_NAME,
        "week": current_week_str,
        "cpu_usage": cpu_usage,
        "memory_usage": memory_usage,
        "network": {
            "up": format_speed(up_speed),
            "down": format_speed(down_speed)
        }
    }

