# --- 3. FastAPI 端点 (与之前相同) ---

@app.get("/", response_class=HTMLResponse)
async def get_home_page():
    return html_content

@app.get("/api/stats")
async def get_stats_http_endpoint():
    return get_system_stats()

@app.websocket("/ws")
async def websocket_endpoint(websocket: WebSocket):
    await websocket.accept()
    print("WebSocket 客户端已连接")
    try:
        while True:
            await websocket.send_json(get_system_stats())
            await asyncio.sleep(1)
    except WebSocketDisconnect:
        print("WebSocket 客户端已断开")
    except Exception as e:
        print(f"WebSocket 发生错误: {e}")


# --- 4. Uvicorn 服务器和系统托盘图标 ---

# Uvicorn 服务器需要在一个单独的线程中运行
# 我们需要一个全局变量来控制服务器的关闭
server_instance = None
server_thread = None

def run_server(host, port):
    """运行 Uvicorn 服务器 (已为 PyInstaller 优化)"""
    global server_instance
    
    # log_level="warning" 减少不必要的日志
    config = uvicorn.Config(app, host=host, port=port, log_level="warning")
    server_instance = uvicorn.Server(config)
    
    # --- [关键修复] ---
    # 为这个新线程显式创建和设置一个新的 asyncio 事件循环
    # asyncio.run() 在打包的EXE的子线程中可能不可靠
    loop = asyncio.new_event_loop()
    asyncio.set_event_loop(loop)
    # ------------------
    
    print(f"服务器线程启动于 http://{host}:{port}")
    
    # 运行服务器，直到 server_instance.should_exit 被设置
    try:
        loop.run_until_complete(server_instance.serve())
    finally:
        loop.close()
        
    print("服务器线程已停止。")

def start_server_thread(host, port):
    """启动服务器后台线程"""
    global server_thread
    server_thread = threading.Thread(target=run_server, args=(host, port), daemon=True)
    server_thread.start()

def on_exit_clicked(icon, item):
    """托盘图标的退出按钮回调"""
    print("退出程序...")
    if server_instance:
        # 这将导致 server_instance.serve() 停止，
        # 从而使 run_until_complete 返回，线程正常退出
        server_instance.should_exit = True
    icon.stop() # 停止托盘图标循环，主线程退出

def start_server_thread(host, port):
    """启动服务器后台线程"""
    global server_thread
    server_thread = threading.Thread(target=run_server, args=(host, port), daemon=True)
    server_thread.start()

def on_exit_clicked(icon, item):
    """托盘图标的退出按钮回调"""
    print("退出程序...")
    if server_instance:
        # 优雅地关闭 Uvicorn
        # 注意：这在某些情况下可能不会立即停止，但 daemon=True 会确保
        # 当主线程(托盘)退出时，服务器线程也会被终止。
        server_instance.should_exit = True
    icon.stop() # 停止托盘图标循环，主线程退出

# --- 5. 主程序入口 ---
if __name__ == "__main__":
    # 在 --noconsole 模式下，sys.stdout 和 sys.stderr 是 None
    # 任何 print() 语句都会导致程序崩溃
    # 我们将它们重定向到一个日志文件
    log_file_path = os.path.join(APP_PATH, "system_monitor.log")
    try:
        # 使用 'a' 模式 (append) 来追加日志, buffering=1 表示行缓冲
        sys.stdout = open(log_file_path, 'a', encoding='utf-8', buffering=1)
        sys.stderr = sys.stdout
    except Exception as e:
        # 如果连日志文件都创建失败，我们也无能为力了
        # 但至少程序不会因为 print 崩溃
        pass 
    
    print(f"\n\n--- [ {datetime.now()} ] 监控服务启动 ---")
    # ----------------------

    # 1. 加载配置
    HOST, PORT, NAME = load_config()
    print(f"配置加载: {HOST}:{PORT}")

    # 2. 检查图标文件是否存在
    icon_to_load = ICON_PATH_BUNDLED
    if not os.path.exists(ICON_PATH_BUNDLED):
        # 尝试从EXE同目录加载 (作为备用方案)
        fallback_icon_path = os.path.join(APP_PATH, ICON_FILE_NAME)
        if os.path.exists(fallback_icon_path):
            print(f"警告: 未找到打包的图标, 使用备用路径: {fallback_icon_path}")
            icon_to_load = fallback_icon_path
        else:
            print(f"错误: 找不到图标文件 '{ICON_FILE_NAME}'！")
            print(f"搜索路径1 (打包): {ICON_PATH_BUNDLED}")
            print(f"搜索路径2 (EXE旁): {fallback_icon_path}")
            # input("按回车键退出...") # 在noconsole模式下这个没用
            sys.exit(1)
    
    print(f"使用图标: {icon_to_load}")

    # 3. 启动 FastAPI 服务器线程
    start_server_thread(HOST, PORT)

    # 4. 创建并运行系统托盘图标 (这将阻塞主线程)
    try:
        image = Image.open(icon_to_load)
        menu = pystray.Menu(
            pystray.MenuItem(f"SystemMonitor [{NAME}]", None, enabled=False),
            pystray.MenuItem(f"Version [{VERSION}]", None, enabled=False),
            pystray.MenuItem(f"Listening on {HOST}:{PORT}", None, enabled=False),
            pystray.Menu.SEPARATOR,
            pystray.MenuItem("Exit", on_exit_clicked)
        )
        icon = pystray.Icon("system_monitor", image, f"System Monitor [{NAME}]", menu)
        
        print("系统监控服务已启动到托盘。")
        icon.run()

    except Exception as e:
        print(f"启动托盘图标失败: {e}")
        # 尝试优雅地停止服务器
        if server_instance:
            server_instance.should_exit = True
        sys.exit(1)
    
    print(f"--- [ {datetime.now()} ] 监控服务已退出 ---")